import{_ as a,o as i,c as o,ao as d}from"./chunks/framework.Cg2N26K4.js";const h=JSON.parse('{"title":"Roadmap","description":"","frontmatter":{},"headers":[],"relativePath":"roadmap.md","filePath":"roadmap.md","lastUpdated":null}'),t={name:"roadmap.md"};function n(r,e,l,c,s,p){return i(),o("div",null,[...e[0]||(e[0]=[d('<h1 id="Roadmap" tabindex="-1">Roadmap <a class="header-anchor" href="#Roadmap" aria-label="Permalink to &quot;Roadmap {#Roadmap}&quot;">​</a></h1><p>This page mirrors the repository roadmap. It is evidence-gated: a capability is public only when code, tests, documentation, validation status, and the R-Julia contract agree.</p><h2 id="Current-Status" tabindex="-1">Current Status <a class="header-anchor" href="#Current-Status" aria-label="Permalink to &quot;Current Status {#Current-Status}&quot;">​</a></h2><p>Phase 0 is complete. Phase 1 has started.</p><p>Implemented:</p><ul><li><p>package scaffold and CI;</p></li><li><p>control/backend markers for the shared planned <code>auto</code>, <code>cpu</code>, <code>threads</code>, <code>cuda</code>, <code>amdgpu</code>, <code>metal</code>, and <code>oneapi</code> vocabulary;</p></li><li><p><code>backend_info()</code> status diagnostics for the planned backend vocabulary;</p></li><li><p><code>formula_status()</code> grammar diagnostics for parsed, reserved, and planned syntax rows;</p></li><li><p><code>validation_status()</code> diagnostics for covered, external, partial, and planned validation rows;</p></li><li><p>planned model-term vocabulary reservations aligned to the R genomic/QTL and standard quantitative-genetic markers;</p></li><li><p>placeholder fitting entry points;</p></li><li><p>pedigree validation and topological sorting;</p></li><li><p>direct sparse <code>Ainv</code> construction for validated pedigrees;</p></li><li><p>optional external R-side <code>nadiv::Mrode9</code> / <code>nadiv::makeAinv()</code> comparator evidence for <code>pedigree_inverse()</code>;</p></li><li><p>low-level animal-model spec validation;</p></li><li><p>dense Gaussian likelihood evaluation with a <code>max_dense_cells</code> guard;</p></li><li><p>sparse REML likelihood evaluation at supplied variance components via the Henderson MME determinant identity;</p></li><li><p>experimental dense variance-component optimization;</p></li><li><p>experimental MME-backed EBV/BLUP aliases, fitted-value, heritability, PEV, reliability, and checked accuracy extraction for dense spec and supplied-variance Henderson MME validation paths;</p></li><li><p>experimental direct payload fitting target for <code>y</code>, <code>X</code>, <code>Z</code>, <code>Ainv</code>;</p></li><li><p>sparse Henderson MME solving at supplied variance components, with a shared R/Julia fixture for Ainv, fixed effects, EBVs, fitted values, and <code>h2</code>;</p></li><li><p>sparse CSC marshalling helper for R sparse matrix slots;</p></li><li><p><code>HSData</code> marker-map metadata validation and genotype-marker alignment checks;</p></li><li><p><code>data_status()</code> diagnostics for <code>HSData</code> component presence, ID-overlap counts, pedigree status, marker-alignment status, and environment-key status;</p></li><li><p>external opt-in R bridge evidence from <code>hsquared</code> head <code>9eabf0d</code>;</p></li><li><p>external R PEV/reliability bridge enrichment evidence from <code>hsquared</code> head <code>8235289</code>; R can merge those fields from exported Julia extractors for tiny/local validation fits while Julia keeps base <code>result_payload()</code> compact.</p></li><li><p>external R EBV/BLUP/accuracy extractor ergonomics evidence from <code>hsquared</code> head <code>afa25f1</code>; Julia mirrors the names locally without adding payload fields.</p></li><li><p>external R supplied-variance Henderson MME bridge evidence from <code>hsquared</code> head <code>00b9e33</code>; R can opt into <code>engine_control$target = &quot;henderson_mme&quot;</code> and supplied variance components, with no log-likelihood, AIC, <code>df</code>, optimizer output, variance-component estimation, AI-REML, or fitted Mrode claim.</p></li><li><p>external R <code>model_spec()</code> preview evidence from <code>hsquared</code> head <code>bacef9c</code>; this previews the v0.1 formula-to-bridge payload without fitting or Julia execution.</p></li><li><p>external R <code>hs_data()</code> parser integration evidence from <code>hsquared</code> head <code>36efbf3</code>; this lets <code>model_spec()</code> and <code>hsquared()</code> read v0.1 model variables from <code>data$phenotypes</code> and resolve <code>pedigree</code> from the bundle while keeping the bridge payload shape unchanged.</p></li><li><p>external R formula-ergonomics evidence from <code>hsquared</code> heads <code>74eef82</code> and <code>39ca990</code>; <code>animal(1 | id)</code> may use the pedigree stored in <code>data = hs_data(..., pedigree = ped)</code>, while explicit <code>animal(1 | id, pedigree = ped)</code> remains the shared portable contract.</p></li><li><p>external R <code>hs_data()</code> environment diagnostics evidence from <code>hsquared</code> head <code>e7fbb31</code>; Julia mirrors the shared-key metadata diagnostics locally in <code>HSData</code>, with no bridge payload or modelling change.</p></li><li><p>external sparse <code>Z</code> bridge marshalling evidence from <code>hsquared</code> head <code>398e019</code>.</p></li><li><p>roadmap documentation for genomics, QTL/eQTL, GLLVM, backend, algorithm, and HPC strategy mirrored from the R twin&#39;s expanded plan at <code>hsquared</code> head <code>2c18b30</code>.</p></li></ul><p>Not implemented:</p><ul><li><p>sparse production animal-model REML/ML or AI-REML fitting;</p></li><li><p>production sparse EBVs/BLUPs, reliability, and prediction error variance;</p></li><li><p>production R-to-Julia fitting bridge;</p></li><li><p>genomic prediction, single-step fitting, marker-effect estimation, marker scans, and QTL/eQTL scans;</p></li><li><p>permanent environment, common environment, maternal/paternal effects, cytoplasmic inheritance, imprinting, dominance, epistasis, and custom relationship/precision kernels;</p></li><li><p>backend execution dispatch, runtime backend availability probing, GPU execution, backend benchmarking, and CPU/GPU numerical agreement tests.</p></li><li><p>APY approximation, Takahashi selected inversion, production AI-REML, Woodbury-backed factor/GLLVM engines, and HPC checkpointing.</p></li></ul><h2 id="Phase-1:-Simple-Gaussian-Animal-Model" tabindex="-1">Phase 1: Simple Gaussian Animal Model <a class="header-anchor" href="#Phase-1:-Simple-Gaussian-Animal-Model" aria-label="Permalink to &quot;Phase 1: Simple Gaussian Animal Model {#Phase-1:-Simple-Gaussian-Animal-Model}&quot;">​</a></h2><p>Next engine targets:</p><ol><li><p>Mrode-style validation and comparator checks;</p></li><li><p>R/Julia decision on whether PEV/reliability should ever become required base bridge payload fields;</p></li><li><p>live Julia <code>HSData</code> object marshalling, relationship-object marshalling beyond sparse <code>Z</code>, and stable production engine controls;</p></li><li><p>production sparse covariance/precision computations;</p></li><li><p>AI-REML or a documented sparse optimizer path;</p></li><li><p>production sparse reliability and prediction error variance.</p></li></ol><h2 id="Later-Phases" tabindex="-1">Later Phases <a class="header-anchor" href="#Later-Phases" aria-label="Permalink to &quot;Later Phases {#Later-Phases}&quot;">​</a></h2><ul><li><p>Phase 2: genomic relationship models, GBLUP, SNP-BLUP, supplied <code>Hinv</code>, and first marker-effect outputs.</p></li><li><p>Phase 3: maternal, paternal, repeatability, common-environment, dominance, cytoplasmic, and inheritance-kernel models.</p></li><li><p>Phase 4: multivariate G matrices with <code>us()</code>, <code>diag()</code>, <code>lowrank(K)</code>, and <code>fa(K)</code>.</p></li><li><p>Phase 5: QTL/GWAS/eQTL scans, LOCO option, multiple testing, and basic plots.</p></li><li><p>Phase 6: non-Gaussian and GLLVM-style animal models, omics, and community examples.</p></li><li><p>Phase 7: CPU/GPU acceleration with CPU, threads, Metal, CUDA, AMDGPU, oneAPI, and portable kernels.</p></li><li><p>Phase 8: HPC and production scaling with checkpointing, disk-backed data, streaming marker scans, distributed computation, and multi-GPU experiments.</p></li></ul><p>Every new public capability must update the status tables, validation debt, tests, docs, and after-task report in the same slice.</p>',14)])])}const u=a(t,[["render",n]]);export{h as __pageData,u as default};
